import React, { useEffect, useState } from 'react';
import { toast } from 'react-toastify';
import { studentAPI } from '../services/api';

const initialForm = {
  studentId: '',
  name: '',
  email: '',
  department: '',
  semester: 1,
  subjects: '',
};

const Students = () => {
  const [students, setStudents] = useState([]);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [formData, setFormData] = useState(initialForm);

  const fetchStudents = async () => {
    try {
      setLoading(true);
      const response = await studentAPI.getAll();
      setStudents(response.data || []);
    } catch (error) {
      toast.error('Failed to load students');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchStudents();
  }, []);

  const onChange = (event) => {
    const { name, value } = event.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleAddStudent = async (event) => {
    event.preventDefault();
    try {
      setSubmitting(true);
      const payload = {
        ...formData,
        semester: Number(formData.semester),
        subjects: formData.subjects
          .split(',')
          .map((subject) => subject.trim())
          .filter(Boolean),
      };

      await studentAPI.add(payload);
      toast.success('Student added successfully');
      setFormData(initialForm);
      fetchStudents();
    } catch (error) {
      toast.error(error.response?.data?.error || 'Failed to add student');
    } finally {
      setSubmitting(false);
    }
  };

  const handleDeleteStudent = async (studentId) => {
    try {
      await studentAPI.delete(studentId);
      toast.success('Student deleted');
      fetchStudents();
    } catch (error) {
      toast.error('Failed to delete student');
    }
  };

  return (
    <div className="space-y-6">
      <div className="bg-white rounded-lg shadow-md p-6">
        <h1 className="text-3xl font-bold text-gray-800 mb-2">Students</h1>
        <p className="text-gray-600">Add and manage student records.</p>
      </div>

      <div className="bg-white rounded-lg shadow-md p-6">
        <h2 className="text-xl font-semibold text-gray-800 mb-4">Add Student</h2>
        <form onSubmit={handleAddStudent} className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          <input
            className="input-field"
            name="studentId"
            placeholder="Student ID"
            value={formData.studentId}
            onChange={onChange}
            required
          />
          <input
            className="input-field"
            name="name"
            placeholder="Full Name"
            value={formData.name}
            onChange={onChange}
            required
          />
          <input
            className="input-field"
            type="email"
            name="email"
            placeholder="Email"
            value={formData.email}
            onChange={onChange}
            required
          />
          <input
            className="input-field"
            name="department"
            placeholder="Department"
            value={formData.department}
            onChange={onChange}
            required
          />
          <input
            className="input-field"
            type="number"
            min="1"
            name="semester"
            placeholder="Semester"
            value={formData.semester}
            onChange={onChange}
            required
          />
          <input
            className="input-field md:col-span-2 lg:col-span-1"
            name="subjects"
            placeholder="Subjects (comma separated)"
            value={formData.subjects}
            onChange={onChange}
          />
          <div className="md:col-span-2 lg:col-span-3">
            <button type="submit" className="btn-primary" disabled={submitting}>
              {submitting ? 'Adding...' : 'Add Student'}
            </button>
          </div>
        </form>
      </div>

      <div className="bg-white rounded-lg shadow-md p-6 overflow-x-auto">
        <div className="flex items-center justify-between mb-4">
          <h2 className="text-xl font-semibold text-gray-800">Student List</h2>
          <button onClick={fetchStudents} className="btn-secondary">
            Refresh
          </button>
        </div>

        {loading ? (
          <p className="text-gray-500">Loading students...</p>
        ) : students.length === 0 ? (
          <p className="text-gray-500">No students added yet.</p>
        ) : (
          <table className="min-w-full">
            <thead>
              <tr className="table-header">
                <th className="px-4 py-3 text-left">ID</th>
                <th className="px-4 py-3 text-left">Name</th>
                <th className="px-4 py-3 text-left">Department</th>
                <th className="px-4 py-3 text-left">Semester</th>
                <th className="px-4 py-3 text-left">Subjects</th>
                <th className="px-4 py-3 text-left">Actions</th>
              </tr>
            </thead>
            <tbody>
              {students.map((student) => (
                <tr key={student.studentId} className="table-row">
                  <td className="px-4 py-3">{student.studentId}</td>
                  <td className="px-4 py-3">
                    <p className="font-semibold">{student.name}</p>
                    <p className="text-sm text-gray-500">{student.email}</p>
                  </td>
                  <td className="px-4 py-3">{student.department}</td>
                  <td className="px-4 py-3">{student.semester}</td>
                  <td className="px-4 py-3 text-sm text-gray-600">
                    {(student.subjects || []).join(', ') || '-'}
                  </td>
                  <td className="px-4 py-3">
                    <button
                      onClick={() => handleDeleteStudent(student.studentId)}
                      className="btn-danger"
                    >
                      Delete
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
};

export default Students;
